from crewai import Agent, Task, Crew
from time import perf_counter

class LatencyTracker:
    def __init__(self):
        self.latencies = {}

    def track_task(self, task_name):
        start = perf_counter()
        def wrapper(func):
            def wrapped(*args, **kwargs):
                result = func(*args, **kwargs)
                duration = perf_counter() - start
                self.latencies[task_name] = self.latencies.get(task_name, []) + [duration]
                if duration > 3.0:
                    print(f'🚨 SLOW TASK: {task_name} took {duration:.2f}s')
                return result
            return wrapped
        return wrapper

# Usage
tracker = LatencyTracker()
research_task = Task(
    description='Research topic...',
    agent=researcher,
    context=[...],
    callback=tracker.track_task('research')
)

from crewai import Crew
from time import perf_counter

class DelegationMonitor(Crew):
    def __init__(self, *args, **kwargs):
        super().__init__(*args, **kwargs)
        self.delegation_times = []

    def kickoff(self):
        start = perf_counter()
        result = super().kickoff()
        duration = perf_counter() - start

        if duration > 10:
            print(f'🚨 SLOW DELEGATION: Crew took {duration:.2f}s')
            for task in self.tasks:
                if hasattr(task, 'execution_time'):
                    print(f'  - {task.description[:50]}...: {task.execution_time:.2f}s')
        return result

# Usage
