from crewai import Agent, Task
from langchain.prompts import PromptTemplate

COMPRESSION_TEMPLATE = """
Context Summary: {context_summary}

Current Task: {task_description}
Previous Output: {last_output}

Respond concisely and directly to the task.
"""

class FastAgent(Agent):
    def __init__(self, *args, **kwargs):
        super().__init__(*args, **kwargs)
        self.context_history = []

    def create_prompt(self, task):
        if len(self.context_history) > 3:
            context_summary = self.summarize_history()
        else:
            context_summary = '\n'.join(self.context_history[-2:])

        compressed_prompt = COMPRESSION_TEMPLATE.format(
            context_summary=context_summary,
            task_description=task.description,
            last_output=self.context_history[-1] if self.context_history else ''
        )
        self.context_history.append(compressed_prompt)
        return compressed_prompt

# Usage
fast_researcher = FastAgent(
    role='Fast Researcher',
    goal='Research quickly...',
    llm=ChatOpenAI(model='gpt-4o-mini', max_tokens=500)
)
